import torch

def compute_task_vector(base_state_dict, finetuned_state_dict):
    """Compute the task vector: delta = finetuned - base"""
    return {k: finetuned_state_dict[k].float() - base_state_dict[k].float()
            for k in base_state_dict.keys()}

def apply_task_vector(base_state_dict, task_vector, lam=1.0):
    """Apply a task vector at strength lambda."""
    return {k: base_state_dict[k].float() + lam * task_vector[k]
            for k in base_state_dict.keys()}

def merge_task_vectors(base_sd, task_vectors, lambdas):
    """
    Merge multiple task vectors: theta = theta_0 + sum(lambda_i * tau_i)
    task_vectors: list of dicts {param_name: delta_tensor}
    lambdas:      list of floats
    """
    merged = {k: base_sd[k].float().clone() for k in base_sd.keys()}
    for tau, lam in zip(task_vectors, lambdas):
        for k in merged:
            merged[k] += lam * tau[k]
    return merged

